import json
import boto3

def lambda_handler(event, context):
    # Example of accessing S3 securely
    s3_client = boto3.client('s3')
    response = s3_client.get_object(Bucket='your-bucket-name', Key='your-object-key')
    data = response['Body'].read()

    # Example of accessing DynamoDB securely
    dynamodb = boto3.resource('dynamodb')
    table = dynamodb.Table('your-table-name')
    table.put_item(Item={'id': '123', 'data': data})

    # Example of publishing to SNS securely
    sns_client = boto3.client('sns')
    sns_client.publish(TopicArn='arn:aws:sns:your-region:your-account-id:your-topic-name', Message='Hello World')

    # Example of sending a message to SQS securely
    sqs_client = boto3.client('sqs')
    sqs_client.send_message(QueueUrl='https://sqs.your-region.amazonaws.com/your-account-id/your-queue-name', MessageBody='Hello World')

    return {
        'statusCode': 200,
        'body': json.dumps('Function executed successfully!')
    }